  export function renderBlocks(blocks: Block[]): JSX.Element {
    return blocks.map(block => {
      switch (block.type) {
        case 'paragraph':
          return <p>{renderRichText(block.paragraph.rich_text)}</p>
        case 'heading_1':
          return <h1>{renderRichText(block.heading_1.rich_text)}</h1>
        case 'heading_2':
          return <h2>{renderRichText(block.heading_2.rich_text)}</h2>
        case 'code':
          return <pre><code>{block.code.rich_text[0].plain_text}</code></pre>
        case 'bulleted_list_item':
          return <li>{renderRichText(block.bulleted_list_item.rich_text)}</li>
        // ... 더 많은 타입
      }
    })
  }

  function renderRichText(richText: RichText[]): string {
    return richText.map(text => {
      let result = text.plain_text
      if (text.annotations.bold) result = <strong>{result}</strong>
      if (text.annotations.italic) result = <em>{result}</em>
      if (text.href) result = <a href={text.href}>{result}</a>
      return result
    })
  }

