  export default async function IdeaPage({ params }: { params: { id: string } }) {
    const idea = await getIdeaById(params.id)
    if (!idea) return <div>아이디어를 찾을 수 없습니다</div>
    return (
      <div>
        <header> {/* 뒤로가기 버튼 또는 링크 */} </header>
        <main className="mx-auto max-w-screen-2xl px-4">
          <h1>{idea.title}</h1>
          <div className="flex gap-4">
            <CategoryBadge category={idea.category} />
            <StatusBadge status={idea.status} />
          </div>
          <div className="text-sm text-gray-600">
            {idea.createdAt} | {idea.updatedAt}
          </div>
          <article className="prose dark:prose-invert">
            {renderBlocks(idea.blocks)} {/* Rich Text 렌더링 */}
          </article>
        </main>
      </div>
    )
  }

  export async function generateStaticParams() {
    const ideas = await getAllIdeas()
    return ideas.map(idea => ({ id: idea.id }))
  }

  export async function generateMetadata({ params }: { params: { id: string } }) {
    const idea = await getIdeaById(params.id)
    return { title: idea?.title, description: idea?.summary }
  }
